function Home() {
  return (
    <div
      className="w-full h-[100vh] flex items-center justify-center p-10"
      style={{
        backgroundImage: "url('/fondo6.jpg')",
        backgroundSize: 'cover',
        backgroundPosition: 'center',
      }}
    >
      <div className="flex items-center gap-10">
        <div className="w-full h-full relative">
          <img
            className="rounded-lg absolute top-0 left-0 z-10 transition-transform transform hover:scale-110"
            width={300}
            height={300}
            src="/Foto1.HEIC"
            alt="Imagen 1"
          />
          <img
            className="rounded-lg absolute top-0 left-10 z-20 transition-transform transform hover:scale-110"
            width={300}
            height={300}
            src="/Foto2.HEIC"
            alt="Imagen 2"
          />
        </div>
        <div className="flex flex-col items-center">
          <h1 className="text-white text-4xl md:text-6xl font-bold text-center">
            ¡Los invitamos a festejar nuestra boda!
          </h1>
          <h2 className="text-white text-4xl md:text-6xl font-bold text-center">
            Anto & Kevin
          </h2>
          <a
            href="#ConfirmAttendance"
            className="text-white text-xl mt-4 underline hover:text-gray-200"
          >
            {`Confirmar asistencia ${'>'}`}
          </a>
        </div>
        <div className="relative">
          <img
            className="rounded-lg absolute top-0 left-0 z-10 transition-transform transform hover:scale-110"
            width={300}
            height={300}
            src="/Foto3.HEIC"
            alt="Imagen 3"
          />
          <img
            className="rounded-lg absolute top-0 left-10 z-20 transition-transform transform hover:scale-110"
            width={300}
            height={300}
            src="/Foto4.HEIC"
            alt="Imagen 4"
          />
        </div>
      </div>
    </div>
  );
}

export default Home;
